/**
 * MedX contrast accessibility runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * WCAG contrast checking for status colors.
 */
const CONTRAST_TOKENS = Object.freeze({
  primary: { value: "a11y-contrast-primary", scope: "a11y" },
  secondary: { value: "a11y-contrast-secondary", scope: "a11y" },
  muted: { value: "a11y-contrast-muted", scope: "a11y" },
  accent: { value: "a11y-contrast-accent", scope: "a11y" },
  surface: { value: "a11y-contrast-surface", scope: "a11y" },
});

const CONTRAST_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const CONTRAST_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const contrastRegistry = new Map();
const CONTRAST_listeners = new Set();
let CONTRAST_seq = 0;

function createContrastId(prefix = "medx-a11y-contrast") {
  CONTRAST_seq += 1;
  return `${prefix}-${CONTRAST_seq}`;
}

function registerContrast(config = {}) {
  const entryId = config.id ?? createContrastId();
  const preset = CONTRAST_PRESETS[config.preset ?? "default"] ?? CONTRAST_PRESETS.default;
  const token = CONTRAST_TOKENS[config.token ?? preset.token] ?? CONTRAST_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: CONTRAST_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  contrastRegistry.set(entryId, entry);
  notifyContrastListeners("register", entry);
  return entry;
}

function updateContrast(id, patch = {}) {
  const entry = contrastRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyContrastListeners("update", entry);
  return entry;
}

function resolveContrast(id) {
  const entry = contrastRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listContrastEntries(filter = {}) {
  let items = Array.from(contrastRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onContrastEvent(listener) {
  CONTRAST_listeners.add(listener);
  return () => CONTRAST_listeners.delete(listener);
}

function notifyContrastListeners(type, entry) {
  for (const listener of CONTRAST_listeners) {
    try {
      listener({ type, entry, registrySize: contrastRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:a11y:contrast] listener error", err.message);
    }
  }
}

function getContrastMetrics() {
  const items = listContrastEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(CONTRAST_TOKENS).length,
    presets: Object.keys(CONTRAST_PRESETS).length,
  };
}

async function runMedxContrast() {
  console.log("[medx:ui:a11y:contrast] runtime initialized");
  console.log(`[medx:ui:a11y:contrast] tokens=${Object.keys(CONTRAST_TOKENS).length} presets=${Object.keys(CONTRAST_PRESETS).length}`);

  const events = [];
  onContrastEvent((e) => events.push(e.type));

  const domains = Object.keys(CONTRAST_SUPPLY_CHAIN);
  const presets = Object.keys(CONTRAST_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerContrast({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "a11y/contrast" },
    });
  }

  const first = listContrastEntries()[0];
  if (first) updateContrast(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getContrastMetrics();
  const resolved = first ? resolveContrast(first.id) : null;

  console.log(`[medx:ui:a11y:contrast] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:a11y:contrast] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:a11y:contrast] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:a11y:contrast] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:a11y:contrast] bootstrap complete");
}

module.exports = runMedxContrast;
